// Merge Salesforce objects into flat JSON matching PDF field names
// Edit the mapping below to match YOUR PDF template fields

const lead = $input.first().json;

// Field mapping: PDF field name -> Salesforce value
// Run 'python run.py discover templates/your.pdf' to see your PDF's actual field names
const pdfData = {
  // Lead fields
  firstName: lead.FirstName || '',
  lastName: lead.LastName || '',
  email: lead.Email || '',
  phone: lead.Phone || '',
  company: lead.Company || '',
  address: lead.Street || '',
  city: lead.City || '',
  state: lead.State || '',
  zipCode: lead.PostalCode || '',
  country: lead.Country || '',
  jobTitle: lead.Title || '',
  notes: lead.Description || '',
  submissionDate: new Date().toISOString().split('T')[0],

  // Add Opportunity fields (uncomment and add a Salesforce node to fetch):
  // dealAmount: opportunity?.Amount?.toString() || '',
  // closeDate: opportunity?.CloseDate || '',
  // dealStage: opportunity?.StageName || '',

  // Add Account fields:
  // accountName: account?.Name || '',
  // accountCity: account?.BillingCity || '',

  // Add Custom Object fields:
  // customField1: customRecord?.Custom_Field__c || '',
};

return [{ json: { data: pdfData, leadId: lead.Id } }];

// Convert base64 PDF to binary file for email/upload
const base64Data = $input.first().json.pdf_base64;
const filename = $input.first().json.filename || 'filled_form.pdf';
const coverage = $input.first().json.coverage;

return [{
  json: {
    filename,
    coverage,
    message: `PDF filled successfully. Coverage: ${coverage?.coverage_pct || 0}%`
  },
  binary: {
    data: {
      data: base64Data,
      mimeType: 'application/pdf',
      fileName: filename,
      fileExtension: 'pdf'
    }
  }
}];

// Log the error for debugging
const errorData = $input.first().json;
console.log('PDF Fill Error:', JSON.stringify(errorData));

return [{
  json: {
    status: 'error',
    message: 'PDF filling failed. Check the API server logs.',
    raw: errorData
  }
}];
